parameters.functionCode:
// Parsea el reporte y extrae métricas clave para el router
var raw = '';
if (items[0].binary && items[0].binary.data) {
  raw = Buffer.from(items[0].binary.data, 'base64').toString();
} else if (items[0].json && items[0].json.fileContent) {
  raw = items[0].json.fileContent;
}

var report;
try {
  report = JSON.parse(raw);
} catch(e) {
  report = { summary: { severity_breakdown: { CRITICAL: 0, HIGH: 0 }, total_issues: 0 } };
}

var summary = report.summary || {};
var severity = summary.severity_breakdown || {};
var ai = report.ai_analysis || {};

return [{
  json: {
    has_critical: (severity.CRITICAL || 0) > 0,
    critical_count: severity.CRITICAL || 0,
    high_count: severity.HIGH || 0,
    total_issues: summary.total_issues || 0,
    at_risk_usd: summary.at_risk_value_usd || 0,
    in_transit_30d: summary.in_transit_over_30d || 0,
    executive_summary: ai.executive_summary || 'Sin análisis IA disponible',
    priority_actions: (ai.priority_actions || []).slice(0, 3),
    reference_date: report.reference_date,
    generated_at: report.generated_at
  }
}];

